oldWay:
/* Had to style every native control individually */
input, select, textarea {
  background: #1e293b;
  color: #e2e8f0;
  border: 1px solid #475569;
}
/* Checkboxes and radio buttons couldn't be reliably dark-styled
   without replacing them entirely */

startingCSS:
.layout {
  display: flex;
  gap: 1rem;
  padding: 1rem;
  background: #0f172a;
  border-radius: 10px;
}

.form-wrapper {
  flex: 1;
  background: #1e293b;
  border-radius: 8px;
  padding: 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.6rem;
}

.label {
  margin: 0 0 0.25rem;
  font-size: 0.72rem;
  font-weight: 600;
  color: #64748b;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

input, select {
  width: 100%;
  padding: 0.4rem 0.6rem;
  border-radius: 4px;
  border: 1px solid #334155;
  font-size: 0.8rem;
}

label {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: #94a3b8;
  font-size: 0.8rem;
}

